python -c "import json, urllib.request, urllib.error; payload={'transcript':'auto apply smoke test retry 3','task':'auto apply smoke test retry 3','tts':False,'auto_apply':True,'agent_key':'reasoner','run_id':None,'output_dir':'E:\AI주식 자동매매','conversation':[]}; data=json.dumps(payload).encode('utf-8'); req=urllib.request.Request('http://127.0.0.1:3010/api/llm/voice/orchestrate', data=data, headers={'Content-Type':'application/json'});
try:
 resp=urllib.request.urlopen(req, timeout=240); body=resp.read().decode('utf-8','replace'); print(resp.status); print(body)
except urllib.error.HTTPError as e:
 body=e.read().decode('utf-8','replace'); print(e.code); print(body); raise
"

$json = @'
{"transcript":"auto apply smoke test retry 4","task":"auto apply smoke test retry 4","tts":false,"auto_apply":true,"agent_key":"reasoner","run_id":null,"output_dir":"E:\AI주식 자동매매","conversation":[]}
'@; try { $res = Invoke-WebRequest -UseBasicParsing -Uri 'http://127.0.0.1:3010/api/llm/voice/orchestrate' -Method Post -ContentType 'application/json' -Body $json; Write-Output $res.StatusCode; Write-Output $res.Content } catch { if ($_.Exception.Response) { $reader = New-Object System.IO.StreamReader($_.Exception.Response.GetResponseStream()); Write-Output $reader.ReadToEnd() } else { $_ | Out-String }; exit 1 }
